INSERT INTO "public"."deyimler" ("id", "deyim", "aciklama", "ornek") VALUES ('1', '(Biri, bir şey) bir yana, dünya bir yana', 'Bir kimseye ya da şeye aşırı ölçüde değer verildiği zaman kullanılır', ''), ('2', 'A`dan Z`ye kadar', 'Bütünüyle, baştan aşağı', 'Bu sınıfın düzeni a`dan z`ye kadar bozuk.'), ('3', 'Aba vakti yaba, yaba vakti aba', 'Kişinin ihtiyaçlarını mevsiminden, sezonundan, vaktinden önce ucu olduğu zamanda karşılaması', ''), ('4', 'Abayı yakmak', 'Bir kimseye gönlünü kaptırmak', 'Bizim oğlan komşu kızına abayı yakmış.'), ('5', 'Abbas yolcu', '1) Yolculuğa çıkmaya kararlı. 2) ölmek üzere olan kimse için şaka yollu söylenir', ''), ('6', 'Abdestinden şüphesi olmamak', 'Kötü bir iş yapmadığına emin olmak', ''), ('7', 'Abes kaçmak (söz)', 'Söylenilen sözün ortama, konuya uygun olmaması', 'İş toplantısında akşamki maçtan bahsetmesi abes kaçtı.'), ('8', 'Abesle iştigal etmek', 'Yersiz, yararsız, boş ve anlamsız şeylerle vakit geçirmek', ''), ('9', 'Abuk sabuk konuşmak', 'Düşünmeden, birbiriyle ilgisi olmayan, tutarsız, saçma sapan söz söylemek', 'Yeter artık, abuk sabuk konuşmalarına daha fazla dayanamayacağım.'), ('10', 'Abur cubur', 'Yararlı olup olmadığı düşünülmeksizin rast gele yenen, yemek yerini tutmayan yiyecekler', 'Çocukların karnını ne diye abur cuburla dolduruyorsun?'), ('11', 'Acı soğuk', 'Keskin, hoşa gitmeyen, çok üşütücü soğuk', 'Acı soğuk insanın iliklerine işliyordu.'), ('12', 'Acı söz', 'İnsanın gönlünü inciten, onuruna dokunan ağır söz', 'Bu acı sözlerine kim katlanır sanıyorsun?'), ('13', 'Acısı içine / yüreğine  işlemek', 'Bir şeyin verdiği acı, üzüntü benliğinde derin iz bırakmak', 'Elindeki tek evi de yanıp kül olunca acısı yüreğine işledi.'), ('14', 'Acısını çıkarmak', '1) Acılığını yok etmek. 2) Önceden uğradığı maddî ve manevî zararı sonradan gidermek. 3) Öç almak', 'Bir gün bana yaptıklarının acısını senden çıkaracağım.'), ('15', 'Aç susuz kalmak', 'Çok yoksul bir duruma düşmek, fakirlikten yaşayamaz hâle gelmek', 'Afrika kıtasının pek çok insanı aç susuz kalmış durumda.'), ('16', 'Açığa vurmak', 'Gizli, saklı bir şeyi herkese duyurmak, ortaya çıkarmak.”Yıllardır içinde sakladığı sırrı mahkemede açığa vurdu.”', ''), ('17', 'Açık alınla', 'Başarı, şeref, övünç ve dürüstlükle', 'Hemen her işten açık alınla çıkar onlar.'), ('18', 'Açık fikirli', 'Olayları, gelişmeleri, yenilikleri iyi anlayıp gereği gibi karşılayan; düşündüğünü olduğu gibi söyleyebilen kimse', 'Bu toplumun açık fikirli insanlara duyduğu ihtiyaç, bugün daha fazladır.'), ('19', 'Açık kalpli /yürekli', 'Samimî, içi temiz, içi dışı bir olan kimse', 'Komşumuz kadar açık kalpli bir adam görmedim.'), ('20', 'Açık seçik', 'Çok açık, çok belirgin, ayrıntılarına kadar görülebilen.”Daha açık seçik konuş da anlayalım ne demek istediğini.”', ''), ('21', 'Açık vermek', '1) Geliri, giderini karşılamamak. 2) Ortaya çıkmaması gereken şeyi farkında olmadan belli etmek', 'Dikkat et de düşmanlarına açık verme.'), ('22', 'Açıkta kalmak (olmak)', '1. İş ve görev bulamamak. 2. Yersiz yurtsuz kalmak. 3. kimilerinin elde ettikleri bir yarardan mahrum olmak', 'Çoluk çocuk açıkta kaldılar fabrika kapanınca.'), ('23', 'Açıktan kazanmak', 'Ortaya hiçbir emek ve sermaye koymadan gelir elde etmek, para kazanmak', 'Günümüz insanı açıktan kazanmayı bir kural hâline getirdi.'), ('24', 'Açlıktan nefesi kokmak', '1) Çok fazla yoksulluk içinde bulunmak. 2) Uzun zaman bir şey yemediği anlaşılmak', 'Dün açlıktan nefesim kokuyordu ama bugün çok şükür karnım tok.'), ('25', 'Açmaza düşmek', 'İçinden çıkılması oldukça güç bir durumda kalmak', 'Beni bu açmazdan ancak çocuklarım kurtarır.'), ('26', 'Adam etmek', '1) Eğitmek, yetiştirmek, belli bir seviyeye getirmek. 2) Tamir edip kullanılır hâle getirmek, bir yeri düzene sokmak', 'Bu arabayı eninde sonunda adam edeceğim.'), ('27', 'Adam sen de (adam!)', 'Bir işin önemli olmadığını, aldırılmaması gerektiğini anlatmak için söylenir', 'Adam sen de, o katılmazsa katılmasın, biz birlikte oynarız.'), ('28', 'Adam sırasına geçmek / girmek', 'Toplumda kendisine daha önce değer verilmezken, artık kendisine önem ve değer verilir olmak', 'Biliyorum, seni de adam sırasına geçiren paran oldu.'), ('29', 'Adama dönmek', 'Hoşa giden bir duruma gelmek, düzelmek', 'Kapılar, pencereler boyanınca ev adama döndü.'), ('30', 'Adamdan saymak', 'Değeri olmadığı hâlde bir kimseye kıymet vermek, saygı duymak', 'Seni adamdan saydım diye mi naz yapıyorsun?'), ('31', 'Adı batmak', 'Adı anılmaz olmak, unutulmak, sözü edilmez olmak', 'Hatırlatmayın, adı batsın o adamın!'), ('32', 'Adı çıkmak', 'Kötü bir şöhret kazanmak', 'Bir kere adı çıkmış, ne yapsa fayda etmiyor, kimse dinlemiyor onu.'), ('33', 'Adı karışmak', 'İyi karşılanmayan bir olayla ilgisinin bulunduğu, o olaya karıştığı söylenmek', 'Soygun işine Ali’nin de adının karıştığı söyleniyor. Doğru mu?'), ('34', 'Adım atmamak', 'Kesinlikle gitmemek, uğramamak, aramamak', 'Bir daha o eve adım atmamaya yeminliyim.'), ('35', 'Adını ağzına almamak', 'Dargınlık, kırgınlık, kızgınlık vb. sebeplerle bir kimseden söz etmemek', ''), ('36', 'Adını koymak', '1) İsim vermek. 2) Bir şeyin karşılığını veya fiyatını kararlaştırmak', 'Önce adını koyalım da ona göre hareket edelim.'), ('37', 'Afiyette olmak', 'Sağlığı, sıhhati yerinde olmak, rahat yaşıyor olmak', 'Hatırladığı kim varsa teker teker arayıp afiyette olup olmadıklarını sordu.'), ('38', 'Aforoz etmek', '1) Kilise birliğinden çıkarmak. 2) Birini yakını olmaktan çıkarmak, ilgiyi kesip uzaklaştırmak, ilişkileri tamamen koparmak', 'Bütün köylü onu aforoz etmekte kararlı.'), ('39', 'Ağır basmak', '1) Ağırlığı fazla gelmek. 2) Bir işte etkili olmak, gücü üstün gelmek, istediğini yaptırmak', 'Politik gücü ağır basınca ihaleyi kazandı.'), ('40', 'Ağır başlı', 'Ciddî, olgun, hareketlerinde ölçülü, işlerini düşüne taşına yapan kimse', 'Ağır başlı olmak insana üstün meziyetler kazandırır.'), ('41', 'Ağır elli', '1) Oldukça yavaş iş yapan, çabuk yapmayan. 2) Vurduğu zaman çok acıtıp can yakan', 'Adamın eli amma da ağırmış, ense köküm hâlâ ağrıyor.'), ('42', 'Ağır gelmek', '1) Ağrına gitmek, onuruna dokunmak. 2) yapılması güç gelmek', 'Bu yaştan sonra inşaat işlerinde çalışmak artık ağır geliyor benim gibi ihtiyara.'), ('43', 'Ağırdan almak', 'Bir işi yapmakta acele etmemek, yavaş davranmak, isteksiz görünmek', 'Hiç sebep yokken işi ağırdan almanı bir türlü anlamıyorum.'), ('44', 'Ağız değiştirmek', 'Daha önce söylediğinin tersini söylemeye başlamak', 'Babasını görünce korkusundan ağız değiştirdi.'), ('45', 'Ağız kalabalığı', 'Birbirini tutmayan, gereksiz, konu dışı sözler', 'Asıl meseleyi ağız kalabalığı ile ört bas edip kaçamazsın!'), ('46', 'Ağız kalabalığına getirmek', 'Birini gereksiz sözler söyleyip çok konuşmak yolu ile şaşırtmak, dikkatini dağıtıp aldatmak', 'Ağız kalabalığına getirip yok pahasına aldı malları.'), ('47', 'Ağız yapmak', 'Birini aldatma, yanıltma, oyalama amacıyla duygularını, düşüncelerini olduğundan başka türlü gösterecek biçimde konuşmak', 'Ne ağız yapıp duruyorsun, gerçeği söylesene!'), ('48', 'Ağız, dil vermemek', '1) Söz söyleyemeyecek kadar hasta olmak. 2) Herhangi bir sebeple hiç konuşmamak, susmak', 'Kurşuna dizilmeyi göze aldılar ama ağız, dil vermediler.'), ('49', 'Ağızdan laf (söz) çekmek / çalmak', 'Bir kişinin bildiği şeyleri ustalıklı konuşmalarda ona sezdirmeden öğrenmek', 'Boşuna uğraşma, ağzından laf çekemezsin onun.'), ('50', 'Ağzı (bir karış) açık kalmak', 'Çok şaşırmak, şaşakalmak', 'Onca seneden sonra sevdiği arkadaşını birden karşısından görünce ağzı açık kaldı.'), ('51', 'Ağzı açık ayran delisi', 'Yeni gördüğü her şeye alık alık bakan, anlamsız bir hayranlıkla seyredip şaşıran', 'Haydi yürü, ağzı açık ayran delisi gibi ne bakıp duruyorsun vitrine.'), ('52', 'Ağzı kalabalık', 'Çok ve manasız, saçma sapan, tutarsız sözler söyleyen', 'Ağzı kalabalık insanlara tahammül etmek çok güç bir iş.'), ('53', 'Ağzı kulaklarına varmak', 'Çok sevinmek, sevindiği her hâlinden belli olmak', 'Takdirname eline verilince sevincinden ağzı kulaklarına vardı.'), ('54', 'Ağzı laf yapmak', 'Güzel, inandırıcı söz söyleme yeteneği olmak', 'Politikacı mı olacaksın, ağzın laf da yapmalı.'), ('55', 'Ağzı var dili yok', '1) Oldukça sessiz, sakin, kendi hâlinde. 2) Konuşmayıp susan, derdini anlatmayan', 'Telâşlanma sakın, ağzı var dili yok o çocuğun, seni hiç üzmez.'), ('56', 'Ağzına (veya ağzının içine) bakmak', '1) Ne diyeceğini beklemek. 2) Onun sözüne göre hareket etmek', ''), ('57', 'Ağzına baktırmak', 'Etkili, güzel konuşarak kendini zevk ile dinletmek, dinleyenleri kendisine hayran etmek', 'O, ağzına baktırmasını bilen ender hatiplerdendi.'), ('58', 'Ağzına bir parmak bal çalmak', 'Amacına ulaşmak için birini tatlı sözlerle bir süre oyalamak, kandırmak; umut verip ikna ederek işini yaptırmak', 'Öyle bir insan ki ağzına bir parmak bal çal, sonra her istediğini yaptır.'), ('59', 'Ağzına lâyık', 'Bir yiyeceğin tadı anlatılırken kullanılır, çok lezzetli yiyecek anlamında', 'Haydi durma, uzan, tam ağzına lâyık bir tatlı!'), ('60', 'Ağzında bakla ıslanmamak', 'Sır saklamayı becerememek, sırrı hemen açığa vurmak', 'Ağzında bakla ıslanmayan bu adama nasıl oluyor da açılıyorsun?'), ('61', 'Ağzından bal akmak / damlamak', 'Çok tatlı konuşmak', 'Onun gibi konuşan birini görmedim, ağzından bal damlıyor sanki.'), ('62', 'Ağzından çıkanı kulağı işitmemek', 'Sözlerini tartmadan, düşünmeden, öfke içinde, nere varacağını hesaplamadan konuşmak', 'İyice çıldırmış olmalısın. Çünkü ağzından çıkanı kulağın duymuyor.'), ('63', 'Ağzından düşürmemek', 'Bir kimseden veya bir şeyden her zaman söz etmek', 'Ölünceye kadar torunu Esma’nın adını ağzından düşürmedi.'), ('64', 'Ağzından girip burnundan çıkmak', 'Çeşitli yollara başvurarak birini bir şeye razı etmek; veya kandırmak', 'Ağzından girip burnundan çıktı ve ondan para koparmayı başardı.'), ('65', 'Ağzından kaçırmak', 'Söylemek istemediği bir şeyi, boş bulunup söyleyivermek', 'Dikkatli ol, lafı ağzından kaçırıp da gideceğimiz yeri söyleme.'), ('66', 'Ağzından laf almak / çekmek', 'Bir kimseyi değişik yollarla ve ustalıkla konuşturup birtakım gizli şeyleri öğrenmek', 'Boşuna uğraşma, ağzımdan laf alamazsın.'), ('67', 'Ağzını açıp gözünü yummak', 'Kızgınlık ile sonunu düşünmeden ağzına gelen kötü sözleri söylemek, karşısındakine hakaret etmek', 'Eve geç gelen kızına ağzını açıp gözünü yumdu.'), ('68', 'Ağzını bıçak açmamak', 'Kırgınlıktan, üzüntüden ya da herhangi bir sebepten ötürü söz söyleyecek durumda olmamak', 'Boşuna uğraşma, evin yanışına öyle üzülmüş ki ağzını bıçak açmıyor.'), ('69', 'Ağzını havaya / poyraza açmak', 'Umduğunu elde edememek, fırsatı kaçırdıktan sonra boş yere beklemek', 'Evi o zaman alacaktın, artık geçti, bundan sonra ağzını havaya aç.'), ('70', 'Ağzını kapamak', '1) Susmak. 2) Çıkarının elden gideceğini düşünerek birinin konuşmasını önlemek', 'Ağzını kapatamazsak konuşup bizi elâleme rezil edecek.'), ('71', 'Ağzını öpeyim / seveyim', 'Sevindirici bir söz söyleyene anlamında kullanılır', 'ne güzel, hoş söyledin'), ('72', 'Ağzının içine bakmak', 'Konuşan bir kimseyi seve seve ve dikkatlice dinlemek', 'Konuşması onları öyle sarmıştı ki ağzının içine bakıyorlardı.'), ('73', 'Ağzının kokusunu çekmek', 'Bir kimsenin dayanılmaz, çekilmez tutum ve davranışlarına katlanmak', 'Yeter artık, daha fazla senin ağız kokunu çekemem.'), ('74', 'Ağzının payını vermek', 'Sert söz ve davranışlarla karşılık vererek bir kimseyi yaptığına pişman etmek', 'Demek öyle, ben de senin ağzının payını vermezsem bana da Hasan demesinler!'), ('75', 'Ağzının tadını bilmek', '1) Güzel yemeklerden anlamak. 2) Bir şeyin güzelini, iyisini bilmek, anlamak', 'Şunlardaki güzelliğe bak, ağzının tadını da biliyorsun hani.'), ('76', 'Ağzıyla kuş tutsa…', '', 'Ağzıyla kuş da tutsa, artık bu eve adım atamaz.'), ('77', 'Ah almak', 'Birinin bedduasını üstüne çekmek', 'Zalimliğine devam edersen daha çok kişinin ahını alacaksın.'), ('78', 'Ahı çıkmak', 'Eziyete uğrayan bir kimsenin yaptığı bedduanın etkisini göstermesi', ''), ('79', 'Ahı yerde kalmamak', 'Ettiği beddua er geç etkisini göstermek', 'Şunu iyi bil ki ey zalim, ahım yerde kalmayacak; yüz üstü sürüneceksin.'), ('80', 'Ahmak ıslatan', 'İnce ince yağan yağmur, çisenti', 'Böyle yürümeye devam edersek bu ahmak ıslatan iliklerimize işleyecek.'), ('81', 'Ahrette on parmağı yakasında olmak', 'Haksızlığa uğrayışını bu dünyada önleyip hakkını alamayanın, öte dünyada (ahirette) kendisine sorumlu olan kimseden davacı olması', 'Hakkımı vermedin ama ahirette on parmağım yakanda olacaktır.'), ('82', 'Akıl defteri', 'Hatırlanıp yapılması gereken şeylerin yazıldığı küçük defter, muhtıra defteri, ajanda', ''), ('83', 'Akıl etmek', 'Herhangi bir önlem ve çareyi zamanında düşünmek, vaktinde hatırlamak', 'Sular kesilecekti ama kovaları doldurmayı akıl edemedim.'), ('84', 'Akıl kârı olmamak', 'Akıllı, dengeli ve ölçülü bir kişinin yapacağı iş olmamak', 'Akıl kârımı şimdi senin yaptığın bu iş?'), ('85', 'Akıl kutusu / kumkuması', 'Çok zeki, akıllı kimse; bilgiç', 'Akıl kutusu mübarek, her meseleyi çözüyor.'), ('86', 'Akıl öğretmek / vermek', 'Herhangi bir konuda yol gösterip tavsiyede bulunmak, bilgi vermek', 'Sana akıl verecek bir adam da mı bulamadın?'), ('87', 'Akıl sır ermemek', 'Bir işin gizli yönlerini, niteliğini, asıl sebebini anlayamamak', 'Senin bu işi nasıl berbat ettiğine hâlâ akıl sır erdiremedim.'), ('88', 'Akıllara durgunluk vermek', 'Çok şaşılacak bir şey olmak', 'Bir görmeliydin o olayı, akıllara durgunluk verecek bir olaydı.'), ('89', 'Akıllı uslu', 'Dengeli, yaramazlık etmeyen, ölçüsüz ve taşkın davranışlarda bulunmayan', 'Senin çocuk pek akıllı uslu görünüyor.'), ('90', 'Akıntıya kürek çekmek', 'Olmayacak, gerçekleşmeyecek bir iş uğrunda boşuna çaba sarf etmek', 'Desene boşuna kürek çekmişiz, olmayacak bu iş.'), ('91', 'Akla karayı seçmek', 'Bir işi başarmak uğrunda çok yorulmak, sonuca kadar çok zahmet çekmek', 'Seni buluncaya kadar akla karayı seçtim.'), ('92', 'Aklı başına gelmek', '1) Zarar gördüğü işlerden uslanıp akıllıca davranmak. 2) Baygınlıktan ayılmak, kendine gelmek', 'Çabuk koşun, nihayet kendine geliyor!'), ('93', 'Aklı başında olmamak', '1) İyi düşünebilir durumda olmamak. 2) Bayılmak, kendisinden geçmek', 'Artık aklı başında olmamak onun işine geliyor sanki, böylece sorumluluktan kurtulacak, rahat edecek.'), ('94', 'Aklı başından gitmek', '1) Çok korkudan veya çok sevinçten ne yapacağını şaşırmak. 2) Kafası çok yorulmuş olduğundan iyi düşünememek', 'Annemi öyle evin ortasında baygın görünce aklım başımdan gitti.'), ('95', 'Aklı çıkmak', 'Titizlikle üzerinde durmak, çok korku geçirmek, çok korkmak', 'Elbisem yırtılacak diye aklı çıkıyor.'), ('96', 'Aklı durmak', 'Şaşırmak, düşünemez bir hâle gelmek', 'Resmi öyle güzel yapmış ki görsen aklın durur.'), ('97', 'Aklı karışmak', 'Ne yapacağını bilememek, bocalamak, şaşırmak', 'Dur hele, bir düşüneyim, söylediklerin aklımı karıştırdı.'), ('98', 'Aklı kesmek', 'Bir şeyin olabileceğine, bir şeyi yapabileceğine inanmak', 'Seninle bu işi başarabileceğime pek de aklım kesmiyor.'), ('99', 'Aklına esmek', 'Daha önce düşünmemiş olduğu şeyi birden yapmaya karar vermek', 'Birden aklına esti, kalkıp sahile indi.'), ('100', 'Aklına gelen başına gelmek', 'Olmasından korktuğu şeyin zarar verici etkisine uğramak', 'Aklıma gelen başıma geldi, evi su bastı.'), ('101', 'Aklına gelmek', '1) Hatırlamak. 2) Bir şeyi yapmayı düşünmek, tasarlamak', 'Aklıma geldi, kalkıp babama gittim.'), ('102', 'Aklına yer etmek', 'Uygun bulduğu bir düşünce kafasına yerleşmek', 'Onun sana söyledikleri aklına yer eder umarım.'), ('103', 'Aklından zoru olmak', 'Tutarsız, dengesiz, ölçüsüz, delice davranışlarda bulunmak', 'Bırak o bıçağı, aklından zorun mu var senin?'), ('104', 'Aklını (bir şeyle) bozmak', '1) Sapıtmak, delirmek. 2) Yalnızca ilgilendiği, üzerine düştüğü şeyle uğraşıp durmak, başka hiçbir mesele düşünmemek', 'Bizim çocuk sinema ile aklını bozdu.'), ('105', 'Aklını almak', 'Çekiciliği, güzelliği ile büyülemek, etkisi altına almak.”Kızın bir bakışı, aklını başından almaya yetti.”', ''), ('106', 'Aklını başına almak / toplamak / devşirmek', 'Mantıksız, ölçüsüz davranışlarda bulunmaktan kendini kurtararak akıllıca bir yola girmek', 'Aklını başına devşir, yoksa bu içki seni öldürecek.'), ('107', 'Aklını başından almak', 'Çok şaşırtmak, düşünemeyecek duruma getirmek.”Gördüğü ev aklını başından aldı.”', ''), ('108', 'Aklını çalmak (çelmek)', '1) Kararından, niyetinden vazgeçirip başka bir yola sokmak. 2) Baştan çıkarmak, ayartmak', 'Aklını çelip onu evlenmeye razı et.'), ('109', 'Aklını peynir ekmekle yemek', 'Akılsızca, şaşkınca, delice işler yapmak', 'Misafirliğe böyle gidilir mi? Sen aklını peynir ekmekle mi yedin?'), ('110', 'Akşamı iple çekmek', 'Gecenin olmasını sabırsızlıkla beklemek', 'Ne güzel bir ziyaret olacak. Akşamı iple çekiyorum.'), ('111', 'Al aşağı etmek', 'Birini bulunduğu yerden, mevkiden indirmek.”Ya, gördün mü, demek ki el oğlu adamı al aşağı ediyormuş bir çırpıda!”', ''), ('112', 'Al birini vur birine /ötekine', 'Hepsi aynı, bir ayarda, hiçbiri işe yaramaz', 'Onlardan söz etme bana. Al birini vur ötekine.'), ('113', 'Al gülüm ver gülüm', '1) Karşılıklı sevgi gösterisi. 2) Çokluk uygun olmayan işlerde birbirinin çıkarını kollamak', ''), ('114', 'Alacağı olsun', 'anlamında göz korkutmak için söylenir', 'Günün birinde ondan öcümü alırım'), ('115', 'Alacağına şahin, vereceğine karga', 'Alırken bütün gücünü kullanan ve kolaylık gösteren, kimsede parasını bırakmayan; verirken ise bin bir güçlük çıkaran, vereceğini geciktirmek için elinden geleni yapan kimse için kullanılır', 'Ne adamsın be! Alacağına şahin, vereceğine karga! Yazıklar olsun!'), ('116', 'Alçak gönüllü olmak', 'Gurur ve kibre kapılmayıp kendini olduğundan daha aşağı düzeyde sayma, başkalarından yüksek görmeme durumu', 'İnsanı insan yapan vasıflardan biri de alçak gönüllü olmaktır.'), ('117', 'Alı al, moru mor', 'Telâş veya yorgunluktan yüzü kıpkırmızı kesilmiş (olarak)', 'Uçağı kalkmak üzere olan babama alı al, moru mor bir şekilde yetişebildim.'), ('118', 'Alıcı gözüyle bakmak', 'Çok dikkatli bakmak, inceden inceye gözden geçirmek', 'Mobilyaya ilk defa alıcı gözüyle baktı.'), ('119', 'Ali Cengiz oyunu', '', 'Bana bir Ali Cengiz oyunu oynadılar ki sormayın gitsin.'), ('120', 'Ali kıran baş kesen', 'Çok zorba, kaba kuvvetle hâkimiyet kuran', 'Mehmet, sınıfın Ali kıran baş kesini olmuştu.'), ('121', 'Ali’nin külâhını Veli’ye, Veli’nin külâhını Ali`ye giydirmek', 'Kendi sermayesi olmadığı hâlde, birinden aldığını ötekine, ötekinden aldığını bir başkasına vererek işini yürütmek', ''), ('122', 'Allah adamı', 'Hile, kötü bilmeyen; hak yol üzerinde olan, Allah`a ibadette kus dini bütün kimse', 'Allah adamı olmalısın dünya da, hem de ahrette iyilik görebilesin.'), ('123', 'Allah Allah!', 'Daha çok şaşkınlık ve hayret hâllerini anlatır', 'Allah Allah! Nasıl oldu bu iş, aklım almıyor?'), ('124', 'Allah aratmasın', 'Yakınılacak bir durumda, bir şeyin hiç bulunmaması hâlindeki sıkıntı anında anlamında kullanılır', 'Allah daha kötüsünü göstermesin'), ('125', 'Allah aşkına', 'Yemin vermek veya yalvarmak için anlamında şaşma, usanç bildirir', 'Allah aşkına şu işi bir daha yapma!'), ('126', 'Allah versin', '1) Dilenciyi savmak için anlamında söylenir. 2) İyi şey elde edenlere memnunluk bildirmek için, kimi zaman da takılma ve şaka için söylenir', 'Allah versin, işlerin gayet iyi görünüyor.'), ('127', 'Allah yarattı dememek', 'Kıyasıya dövmek, çok hırpalamak', 'Adamlar hırsıza bir giriştiler ki Allah yarattı demediler.'), ('128', 'Allah’ın belâsı', 'Varlığı üzüntü veren, varlığından huzursuz olunan şey', 'Allah’ın belâsı adam yine çıktı ortaya.'), ('129', 'Allayıp pullamak', 'Kötü görünüşü kapatmak için bir şeyi süslemek, donatmak', 'Hurda arabaları allayıp pullayıp pazara çıkarmışlar.'), ('130', 'Alnı açık yüzü ak (olmak)', 'Herhangi bir ayıbı, çekinecek bir durumu olmamak, iffetli ve şerefli olmak', 'İşte alnı açık yüzü ak meydandayım; çıksınlar karşıma.'), ('131', 'Alnını karışlamak', '1) Bir işin çok güç olduğunu, yapılamayacak kadar zor olduğunu anlatır. 2) Küçümseyerek meydan okumak, tehdit etmek', 'Beni polise bildirenin alnını karışlarım.'), ('132', 'Alnının akıyla', 'Küçümsenecek, ayıplanacak bir duruma düşmeden; tertemiz, şerefiyle, başarılı olarak', 'Bu işten alnımın akıyla çıkacağım inşallah.'), ('133', 'Alnının kara yazısı', 'Kötü talih, baht', 'Ne yapayım, alnımın kara yazısı böyle imiş.'), ('134', 'Alt yanı çıkmaz sokak', 'Sonuç alınmayacak iş, umutsuz durum', 'Çobanlık mı, dağ tepe dolaş dur, alt yanı çıkmaz sokak vesselâm.'), ('135', 'Altı alay, üstü kalay', 'İçi dışı bir olmayan; dışı süslü, içi berbat', 'Altı alay üstü kalay bir dolaba benziyor bu.'), ('136', 'Altı kaval, üstü şeşhane /Şişhane', 'Daha çok giyim için anlamında kullanılır', 'Çabuk çıkar şu üzerindeki altı kaval üstü şeşhane elbiseyi, yoksa rezil olacaksın el âleme.'), ('137', 'Altın babası', 'Çok zengin, parası çok olan kimse', 'Adam altın babası, her istediğini kolayca yaptırıyor.'), ('138', 'Altın bilezik', 'Para getiren, hayat boyunca geçimi sağlamaya yarayan sanat ve meslek', 'Şimdiden bir altın bilezik sahibi ol ki yarın rahat edesin.'), ('139', 'Altında kalmamak', '1) Bir şeyi karşılıksız bırakmamak. 2) Bir şeyin üstesinden gelmek', 'Bana verdiği işin altında kalmayacağım.'), ('140', 'Altından Çapanoğlu çıkmak', 'Girişilen bir işte başa dert olacak bir durumla, umulmayan bir tehlike ile karşılaşmak', 'Bana öyle geliyor ki bu işin altından Çapanoğlu çıkacak.'), ('141', 'Altından girip üstünden çıkmak', 'Bir serveti, bir parayı, bir kaynağı gereksiz yere, düşüncesizce, sorumsuzca harcayıp kısa zamanda bitirmek', 'Bir ayda o kadar paranın altından girip üstünden çıktı.'), ('142', 'Altından kalkmak', 'Bir zorluğu yenip işi başarmak', 'Telâşlanma, işin altından kalkacaktır o.'), ('143', 'Altını çizmek', 'Bir şeyin (daha çok sözün) önemini belirtmek, üzerine dikkati çekmek, vurgulamak', 'Altını çize çize söylüyorum. Eninde sonunda sen de geleceksin.'), ('144', 'Altını üstüne getirmek', '1. Bir şeyi bulmak için aramadık yer bırakmamak. 2. Söz ve davranışlarıyla çevreyi birbirine düşürmek, karmakarışık etmek', 'Adam iki çift laf etti. Topluluğun altını üstüne getirdi.'), ('145', 'Altmış altıya bağlamak', 'O an ki durumu temelli olmayan bir çözümle kurtarmak veya bir işi kesin neticeye vardırmış gibi görünmek', 'İnsanları altmış altıya bağlamakta üstüne yoktur onun.'), ('146', 'Alttan / aşağıdan almak', 'Sert konuşan birine karşı yumuşak, olumlu, onu haklı görüyormuş gibi tavır almak', 'Amacına ulaşmak istiyorsan onunla konuşurken alttan al, pes perdeden konuş.'), ('147', 'Aman dedirtmek (amana getirmek)', 'Karşı koyan birini boyun eğmek zorunda bırakmak, teslim olmaya zorlamak', 'Düşmana aman dedirtmek boynumuzun borcu oldu artık.'), ('148', 'Aman dilemek', 'Önce direnirken zor karşısında boyun eğip canının bağışlanmasını istemek, galip gelenin merhametine sığınmak', 'Aman dileyene kılıç kalkmaz.'), ('149', 'Aman vermemek', '1) Göz açtırmamak, rahat bırakmamak. 2) Düşmanı acımayıp öldürmek, merhamet etmemek', 'Böyle kahpe insanlara sakın aman vermeyin!'), ('150', 'Amana gelmek', 'Teslim olmak, önce direnirken zor karşısında boyun eğmek', 'Nihayet düşman amana geldi.'), ('151', 'Ana baba günü', '1. Mahşer günü. 2. Sıkıntılı kalabalık; telâşlı, tehlikeli, kimsenin kimseyi tanımadığı kalabalık', 'Yangın yeri ana baba gününe dönmüştü.'), ('152', 'Ana kuzusu', 'Çok küçük yaşta, kucakta taşınan çocuklar, sıkıntıya ve güç işlere alışkın olmayan, biraz nazlı ve hassas çocuklar veya gençler için kullanılıyor. Mesela,', 'Bu ağır torbayı kaldıramıyor, tam bir ana kuzusu!'), ('153', 'Anan yahşi, baban yahşi', '1. Sıkıntılı bir durum içinde olmak. 2. Paraca darlığa düşmek', ''), ('154', 'Anası ağlamak', 'Sıkıntı içinde (olmak)', ''), ('155', 'Anasından doğduğuna pişman', 'Üzücü, sıkıntı verici bir durumla karşılaşmak', ''), ('156', 'Anasını ağlatmak', 'bir kimseye çok sıkıntı çektirmek, çok eziyet etmek. "Kolay sanma, adamın anasını ağlatırlar', ''), ('157', 'Anasının gözü', 'çok düzenci, çok dalavereci, çok açıkgöz, hileci, çıkarcı (kimse)', ''), ('158', 'Anasının nikâhını istemek', 'satacağı bir şeye ya da yapacağı bir işe, bir hizmete değerinin çok üstünde para istemek', ''), ('159', 'Araya girmek', '1) İki kişinin arasındaki bir işe karışmak. 2) Araları bozuk olan iki kişiyi uzlaştırmaya çalışmak. 3) Yapılmakta olan bir işin yapılmasını geciktirmek', 'Araya başka işler girince seninkini yapamadım, kusura bakma.'), ('160', 'Araya koymak', 'Bir işte sözü geçen bir kimsenin aracılığına başvurmak', 'Genel müdürü araya koyup senin işe alınmanı sağlayacaklardır.'), ('161', 'Arı kovanı gibi işlemek', 'Girip çıkanı, gelip gideni çok olmak', 'Şu seçim dolayısıyla doktorun evi arı kovanı gibi işliyor.'), ('162', 'Ârif olan anlasın /anlar', 'Üstü örtülü olarak söylenen bir sözün, anlayışı kuvvetli kimselerce anlaşılabileceğini belirtmek için kullanılır', ''), ('163', 'Arka / sırt çevirmek', 'Birine eskiden duyduğu ilgiyi göstermemek, yabancı gibi davranmak', 'İşlerim bozulunca bana sırt çevirdi.'), ('164', 'Arka arkaya vermek', 'Birbirini korumak, kollamak, için birleşmek; dayanışmak, yardımcı olmak', 'Arka arkaya verirsek karşımızda hiçbir güç duramaz.'), ('165', 'Arka kapıdan çıkmak', 'Özellikle bir eğitim kurumundan, bir iş yerinden hiçbir varlık gösteremeden, bir şey öğrenemeden ayrılmak', 'Övünüp durma, bilgine bakılırsa sen o okulun arka kapısından çıkmışsın.'), ('166', 'Arkadan söylemek', 'Bir kimsenin bulunmadığı yerde onun hakkında ileri geri konuşmak, dedikodusunu yapmak, çekiştirmek', 'Adamın arkasından söylemeye utanmıyor musun?'), ('167', 'Arkadan vurmak', 'Kendisine inanan, güvenen bir kimseye gizlice kötülük etmek', 'Onun beni arkamdan vuracağı hiç aklıma gelmezdi.'), ('168', 'Arkası /sırtı yere gelmemek', '1) Sarsılmamak, sağlam ve sağlıklı durumunu sürdürmek. 2) Hiç yenilgi yüzü görmemek', 'Arkası yere gelmemiş bir adam olarak kalmalı o.'), ('169', 'Arkasına düşmek', '1. Birini gözden ayırmayarak arkasından gitmek. 2. Bir işi sona erdirmek için çok sıkı çalışmak', 'Arkasına düşmezsen nasıl elde edeceksin o evi?'), ('170', 'Arkasında dolaşmak / gezmek', 'Bir işi sonuca bağlamak için ilgili yerlere giderek görüşme fırsatı aramak, onların yardımını sağlamak', ''), ('171', 'Arkasını (birine) vermek', 'Bir kimsenin himayesinden güç almak', 'Arkasını kaymakama vermiş pervasızca konuşuyor, yolu burdan geçireceğim diyor.'), ('172', 'Arkasını getirememek', 'Başladığı işi sürdürüp sona erdirememek, sonuçlandıramamak', 'Ne tembel adamsın, şu işin arkasını getiremedin hâlâ!'), ('173', 'Arkasını sıvamak', 'İltifat etmek, okşamak, övmek, birisini bu yolları kullanarak bir işe sevk etmek', 'Arkasını sıvayarak yaptırıyorum her işi bu çocuğa.'), ('174', 'Armudun sapı var, üzümün çöpü var demek', 'Hiçbir şeyi beğenmemek, her şeyin bir kusurunu bulmak', ''), ('175', 'Armut piş, ağzıma düş', 'Bir işin hiç emek harcamadan olmasını, kendiliğinden hazır olup ayağına gelmesini bekleyenlerin durumunu anlatmak için kullanılır', ''), ('176', 'Arpa boyu kadar gitmek', 'Çok az ilerlemek', 'Onca çabaya rağmen arpa boyu kadar gidebildim ancak.'), ('177', 'Arpacı kumrusu gibi düşünmek', 'Derin derin ne yapacağını bilemeden, çaresizlik içinde düşünüp durmak', 'Öyle arpacı kumrusu gibi ne düşünüp duruyorsun?'), ('178', 'Arpalık yapmak', 'Bir yeri sürekli çıkar kaynağı olarak kullanmak, sömürmek', 'Batılılar ülkemizi arpalık yaptılar âdeta.'), ('179', 'Askıda kalmak', 'Bir engel çıkması dolayısıyla bir işin sonuca varamaması, yapılamayıp öylece kalması', 'Senin gelmemen yüzünden bütün işler askıda kaldı.'), ('180', 'Askıya almak', '1) Geciktirmek, belirsiz olarak ertelemek, bir işi zamanında yapmayıp savsaklamak. 2) Altı boşalmış yapıyı dikmelerle tutturarak yıkılmaktan kurtarmak', 'Söyle ona, o adamların tayin işlerini askıya alsın.'), ('181', 'Askıya çıkarmak', 'Evlenecek kimselerin nikâhtan önceki durumlarını gösterir belgelerin, belirli bir süre için ilgili dairede görünür bir yere asılması, ilân edilmesi', ''), ('182', 'Astarı yüzünden pahalı olmak', 'Bir işin ayrıntısına ödenen paranın aslına ödenen paradan fazla olması, gerçek değerinden fazlaya mal olması', 'Elbiseyi diktin ama astarı yüzünden pahalı oldu.'), ('183', 'Astığı astık, kestiği kestik', 'Davranışlarından dolayı kimseye hesap vermeyen, istediği gibi davranan, çok sert kimseler için kullanılır', ''), ('184', 'Aşağı kurtarmaz', '1) Bundan ucuza verilmez. 2) Daha aşağı bir durumu kendine lâyık görmez', 'Israr etme, bu araba daha aşağı kurtarmaz.'), ('185', 'Aşağı tükürsen sakal, yukarı tükürsen bıyık', 'Sakıncalı oluşları eşit olan iki karşıt davranıştan birine karar verememe zorunluluğunu anlatmak için kullanılır', ''), ('186', 'Aşağıdan almak', 'Sert konuşan kimselere karşı yumuşak bir dil kullanmak', 'Biraz aşağıdan alırsan onun sana zarar vermesini kolayca önlersin.'), ('187', 'Aşık atmak', 'Birisiyle yarışmak, özellikle kendisinden üstün birisiyle yarış etmek', 'Sen benimle aşık atacak biri değilsin.'), ('188', 'At oynatmak', '1) Ata hüner göstermek. 2) Bildiği ve istediği gibi davranmak. 3) Belli bir alanda üstünlük kurmak', 'Meydan adamlara kaldı, istedikleri gibi at oynatıyorlar.'), ('189', 'Ata et, ite ot vermek / yedirmek', 'Uygunsuz iş yapmak; birbirini tamamlayan, birbirine uyan unsurları ters kullanmak; kişilere işlerine yaramayan şeyi, ilgili olmadıkları görevi vermek', 'Ata et, ite ot verilen bir ülkede dirlik düzenlik mi olurmuş?'), ('190', 'Ateş almak', '1) Yanmak, tutuşmak. 2) Ateşli silâhın patlaması. 3) Telâşlanmak, öfkelenmek, heyecanlanmak, coşmak', 'Silâh birden ateş aldı.'), ('191', 'Ateş bacayı sarmak', 'Bir iş ya da olay önüne geçilemez, tehlikeli bir durum almak', 'Ateş bacayı sarmadan çabuk gidelim buradan!'), ('192', 'Ateş basmak', 'Aşırı ölçüde sıkılmak, heyecanlanmak, utanmak sonucu vücutta sıcaklığın artması, yüzün kızarması', 'O paha biçilmez vazoyu kırınca bedenini birden bire ateş bastı.'), ('193', 'Ateş kesilmek', '1) Çok kızgın, öfkeli davranışlar göstermek. 2) Çok çalışkan, hareketli ve becerikli olmak. 3) Ateşli silâhlarla yapılan atışa son vermek', 'Taraflar ateş kesilmesine razı olmadılar.'), ('194', 'Ateş pahası', 'Çok pahalı', 'Yeni daireler ateş pahası, nasıl alacağız?'), ('195', 'Ateş püskürmek', 'Çok öfkeli olmak, ağır sözler söylemek', 'Öğretmen kapıyı kıran öğrencilere ateş püskürdü.'), ('196', 'Ateşe atmak', 'Birini çok tehlikeli bir işe bile bile sokmak', 'Hiç aldırmadan, biricik kızını o adamla evlendirip ateşe atamazsın değil mi?'), ('197', 'Ateşe tutmak', '1) Ateşli silâhla mermi atmak. 2) Bir şeyi ateşin üzerinde tutarak ısıtmak', 'Zalim askerler zavallı köylüleri yaylım ateşine tuttular.'), ('198', 'Ateşe vermek', '1) Bir yeri bilerek yakıp yok etmek. 2) Aşırı ölçüde telâşlandırmak. 3) Bir toplumu, bir ülkeyi kargaşalık içine sürükleyerek yıkıma uğratmak', 'Dış güçler yerli işbirlikçilerle anlaşarak ülkeyi ateşe verdiler.'), ('199', 'Ateşten gömlek', 'İçinde bulunulan acı, sıkıntılı, dayanılmaz durumu anlatmak için söylenir', 'İflas etmem, ateşten gömlek giymem demektir.'), ('200', 'Atı alan Üsküdar`ı geçti', '', 'Sen daha dur, atı alan Üsküdar`ı çoktan geçti.'), ('201', 'Atı eşkin, kılıcı keskin', 'Her bakımdan güçlü, dilediğini yapabilir', 'Zalimlere karşı durmak mı istiyorsun? Atın eşkin, kılıcın keskin olmalı!'), ('202', 'Atıp tutmak', '1) Kendi gücünü aşacağı işler yapacağını söylemek, abartılı konuşmak. 2) Birisinin arkasından ileri geri konuşmak, kötü sözler etmek', 'Yüzüne karşı söyle, arkasından atıp tutma adamın.'), ('203', 'Atsan atılmaz, satsan satılmaz', 'İşe yaramadığı, sıkıntı verdiği hâlde vazgeçilemeyen şeyler ve kimseler için kullanılır', 'Ne yapayım, kardeş işte! Atsan atılmaz, satsan satılmaz!'), ('204', 'Avucunu yalamak', 'Umduğunu ele geçirememek, beklediğini elde edememek', 'Avucunu yalamak istemiyorsan harekete geç, sen de çalış.'), ('205', 'Avucunun içine almak', 'Birini her dediğini yapar duruma getirmek, baskı ve etkisi altına almak', 'Kaymakam bütün kasabalıyı avucunun içine aldı.'), ('206', 'Ayağa düşmek', '1) Bir şeyin değerini kaybetmesi. 2) Yalvarır duruma gelmek. 3) İşe ilgisiz ve yetkisiz kimseler karışır olmak', 'Sevinmeyin boşuna, bu işi ayağa düşürmeyeceğim hiçbir zaman.'), ('207', 'Ayağı (ayakları birbirine) dolaşmak', 'Yürürken herhangi bir sebepten ötürü ayakları birbirine takılmak, sendelemek', 'Korkusundan zavallının ayakları birbirine dolaştı.'), ('208', 'Ayağı / ayakları suya ermek / değmek', 'Neden sonra aklı başına gelmek, bir şeyin aslını anlamak, beklenen biçimde olmadığını kavramak', 'Toy olduğu için doğruyu göremiyor, onun da ayağı suya erecek bir gün.'), ('209', 'Ayağı düşmek', 'Bir yere uğramak, o yer yolu üzerinde bulunmak, yolu düşmek', 'Bu rezillikten sonra onun ayağının buralara düşeceğini sanmam artık.'), ('210', 'Ayağı düze basmak', 'İşleri iyi gitmek, zorlukları yenerek rahata kavuşmak', 'Şu borcu da ödedik mi ayağımız düze basacak inşallah.'), ('211', 'Ayağı ile gelmek', '1) Kendi isteği ile gelmek. 2) Çok fazla emek sarf edilmeden elde edilmek', 'Adam ayağı ile geldi dayak yemeye.'), ('212', 'Ayağına bağ olmak', 'Bir işini yapmasına, bulunduğu yerden ayrılmasına engel olmak', 'Bu çocuk ayağıma bağ oldu, onu bırakıp da bir yere gidemiyorum.'), ('213', 'Ayağına dolaşmak / dolanmak', '1) Birisinin yaptığı işe engel olmak. 2) Başkasına yaptığı kötülük kendi başına gelmek', 'Şu köpeği birisi çıkarsın atölyeden, insanın ayaklarına dolanıyor.'), ('214', 'Ayağına gitmek', 'Büyüklük taslamadan alçak gönüllülük edip birinin yanına varmak', 'O baban senin, ayağına gitmelisin.'), ('215', 'Ayağına kapanmak', 'Kendini küçük düşürerek yalvarıp yakarmak', 'İnsan ne birisinin ayağına kapanmalı, ne de birisini ayağına kapandırmalı.'), ('216', 'Ayağını denk almak', 'Birilerinin kendisine karşı yapacakları muhtemel kötülüklere karşı uyanık davranmak, tedbirli olmak', 'Eğer ayağını denk almazsan o adamlar başına bir iş açacaklar senin.'), ('217', 'Ayağını kaydırmak', 'Bir yolunu bularak birini bulunduğu işten, mevkiden uzaklaştırmak', 'Adamcağızın hiç suçu yokken ayağını kaydırdılar, şimdi aç susuz dolaşıyor.'), ('218', 'Ayağını kesmek', '1) Bir yere gitmez, uğramaz olmak. 2) Birini bir yere artık uğramaz duruma getirmek', 'Öyle korkutun ki o adamın ayağı kesilsin bu meyhaneden?'), ('219', 'Ayağını sürümek', '1) Verilen bir görevi ağırdan yapmak. 2) Bir yerden ayrılmak üzere bulunmak. 3) Ölmek üzere olmak. 4) Halk inanışına göre birinin gelmesi, ardından başkalarının da gelmesine yol açmak', 'Ayağını mı sürüdün ne, senden sonra gelen misafirlerin sayısını Allah bilir ancak!'), ('220', 'Ayağını yorganına göre uzatmak', 'Gelirini giderine uydurmak, harcamalarda geliri aşmamak', 'Ayağını yorganına göre uzatmazsan ileride aç kalırsın.'), ('221', 'Ayağının altına almak', '1) Acımasızca, tekmelerle kıyasıya dövmek. 2) Bir şeyi küçük görerek ondan faydalanma yoluna gitmemek, o şeyi tepmek', 'Önüne serilen bütün nimetleri ayağının altına aldı hiç tınmadan.'), ('222', 'Ayağının tozuyla', 'Henüz dinlenmeden, yoldan gelir gelmez', 'Adamı ayağının tozuyla kodese tıktılar.'), ('223', 'Ayak altında kalmak', '1. Hor görülüp aşağılanmak, değer verilmemek. 2. İnsanların sık gelip geçtiği yerde, kalabalık içinde kalmak', 'Seyyar satıcıların pek çoğu ayak altında kalınacak bir yeri seçerler.'), ('224', 'Ayak atmamak', 'Bir yere hiç gitmemek', 'O kente ayak atmadım henüz.'), ('225', 'Ayak takımı', 'İşe yaramaz, bilgisiz, görgüsüz, kaba, serseri, değersiz kimselerin bütünü', 'Mahallemizde ayak takımı gittikçe çoğalıyor.'), ('226', 'Ayak uydurmak', '1) Adımlarını başkasınınkine uydurmak. 2) Kendi gidiş ve davranışını başkasınınkine benzetmek', 'Bu bozuk topluma ayak uydurmak zorunda değiliz.'), ('227', 'Ayak üstü / üzeri', '1) Kısa süre içinde, acele olarak. 2) Ayakta durarak, ayakta dikilerek', 'Gel de şu büfede ayak üstü atıştıralım biraz.'), ('228', 'Ayaklar altına almak', 'Önem verilmesi gereken şeyleri hiçe saymak, çiğnemek', 'Babasının onun için verdiği emekleri ayaklar altına alarak o serseriliği seçti.'), ('229', 'Ayakları geri geri gitmek', 'Bir yere istemeye istemeye, gönülsüz gitmek', 'Hoşlanmadığım bu insanların yanına yaklaştıkça ayaklarım geri geri gitmeye başladı.'), ('230', 'Ayaklı kütüphane', 'Çok şey okumuş, her sorulana cevap veren, çok şey bilen, okudukları aklında kalmış kimse', 'Adam ayaklı kütüphaneydi sanki!'), ('231', 'Ayakta kalmak', '1) Bir zorluk karşısında yıkılmamak, çökmemek. 2) Oturacak yer bulamamak', 'Gemi öyle kalabalıktı ki hepimiz ayakta kaldık.'), ('232', 'Ayıkla pirincin taşını', 'Bir işin oldukça karışık, dolaşık, içinden çıkılması güç olduğunu anlatmak için kullanılır', 'Durup dururken adama olmadık sözler söylemiş, şimdi ayıkla pirincin taşını!'), ('233', 'Ayranı kabarmak', 'Öfkelenmek, kızıp bağırmak; coşmak', 'O konuştukça adamın elleri titriyor, ayranı kabardıkça kabarıyordu.'), ('234', 'Ayvaz kasap hep bir hesap', '', 'Ha öyle ha böyle, ikisi de bir; hangi yolu seçersek seçelim aynı sonuca varır'), ('235', 'Ayyuka çıkmak', '1) Pek yükselmek (ses için). 2) Herkesçe duyulmak, yayılmak (dedikodu için)', 'Öyle kızgındı ki sesi ayyuka çıkıyordu.'), ('236', 'Aza çoğa bakmamak', 'Eline geçenle yetinmek, tok gözlü olmak', ''), ('237', 'Azizlik etmek', 'Şaka ile takılmak, muziplik etmek, şaka ile aldatmak', 'Osman azizlik etmeye bayılır.'), ('238', 'Babasının hayrına', '', 'Hiçbir çıkar elde etmeden, sadece İyilik olsun diye'), ('239', 'Bacak kadar', 'Ufak tefek; kısa boylu (kimse)', ''), ('240', 'Badire(yi) atlatmak', 'Tehlikeli durumu geçiştirmek', ''), ('241', 'Bağ bozmak', 'Mevsim sonunda bağdaki üzümleri toplamak', ''), ('242', 'Bağrı yanık', 'Çok dertli, acılı (kimse)', ''), ('243', 'Bahar başına vurmak (birinin)', '1. Havalar iyice ısınmadan İnce giyinmek. 2. Coşkun, taşkın, aşırı davranışlarda bulunmak', ''), ('244', 'Bahis açmak (bir şeyden, kimseden)', 'Onun hakkında konuşmaya başlamak, ondan söz etmek', ''), ('245', 'Bahse girmek (biriyle)', 'Onunla herrjangi bir konuda kendi görüşünün doğru olduğuna ilişkin iddiaya girmek', ''), ('246', 'Bahse tutuşmak (biriyle)', 'Karşılıklı bahse girmek; iddialaşmak', ''), ('247', 'Bahtı açık', 'İşleri yolunda giden; talihi açık, şansı açık, kısmeti açık', ''), ('248', 'Bahtı bağlı olmak', '1. İşleri İstediği gibi yürümemek. 2. Evlenecek çağa gelmiş kıza kısmet çıkmamak; kısmeti bağlı olmak', ''), ('249', 'Bahtı kara', 'Talihi kötü olan', ''), ('250', 'Bahtına küsmek', 'İşlerin ters gitmesi yüzünden karamsar olmak; şan sına küsmek, talihine küsmek', ''), ('251', 'Bakış açısı', 'Bir olayı, durumu belirli bir açıdan, yönden inceleme; görüş açısı', ''), ('252', 'Bakkal defteri', 'Düzensiz, karalanmış, yıpranmış defter', ''), ('253', 'Bal gibi', 'Pekâlâ, adamakıllı, çok iyi, gereği gibi', ''), ('254', 'Balık eti, balık etinde', 'Şişman değil, ama dolgunca', ''), ('255', 'Balık istifi', 'Çok sıkışık , üst üste, kalabalık olarak', ''), ('256', 'Balık kavağa (kurbağa ağaca) çıkınca', '', 'Olmayacak şeyler olursa'), ('257', 'Balon uçurmak', 'Asılsızca haber yaymak', ''), ('258', 'Baltayı taşa vurmak', 'Farkında olmadan karşısındakini rahatsız ede cek, kızdıracak söz söylemek', ''), ('259', 'Bam teline basmak (dokunmak) (birinin)', 'Bir kimseyi duyarlı oldu ğu bir konuda kızdıracak söz söylemek, davranışta bulunmak', ''), ('260', 'Bana (sana, ona) göre hava hoş', '', 'Öyle ya da böyle olması benim (senin, onun) için fark etmez.'), ('261', 'Bana mısın dememek', 'Zorlu bir işe, etkene vb’ye dayanmak, bunlar dan hiç etkilenmemek', ''), ('262', 'Bardağı taşıran son damla', 'Sonunda insanın sabrını tüketen, olum suz tepki yaçatan söz, davranış vb', ''), ('263', 'Bardaktan boşanırcasına', '(Yağmur için) Çok miktarda, şiddetli', ''), ('264', 'Barut fıçısı gibi', '1. Her an bir çatışmanın çıkabileceği olasılığı bulu nan (yer). 2. Çok kızgın, öfkeli, sert (kimse)', ''), ('265', 'Barut kokusu gelmek (burnuna)', 'Savaş ya da tehlikeli bir şey olacağını sezmek', ''), ('266', 'Basıp geçmek', '1. Önündekini geçmek. 2. Ona uğramamak. 3. Ona Önem vermemek', ''), ('267', 'Basıp gitmek', 'Bir yerden çabucak ayrılmak, uzaklaşmak', ''), ('268', 'Basireti 